import{_ as a}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as o,a as e,e as t,r as d,o as l}from"./app-MOk6SBbl.js";const c={};function r(i,n){const s=d("Mermaid");return l(),o("div",null,[n[0]||(n[0]=e(`<h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言"><span>引言</span></a></h2><blockquote><p>线上订单突然无法取消，排查半小时才发现是 <strong>MySQL 锁超时</strong>。</p></blockquote><p>这种问题在生产环境并不罕见——一个未提交的事务持有行锁，后续所有请求全部阻塞，直到 <code>innodb_lock_wait_timeout</code>（默认 50 秒）超时报错。更可怕的是，如果找不到持有锁的事务，你连 kill 都不知道该 kill 哪个。</p><p>本文带你完整走一遍 MySQL 锁超时的排查链路，从发现问题到定位代码，逐步掌握 InnoDB 锁竞争的诊断方法。读完你将掌握：</p><ul><li>如何利用 <code>information_schema</code> 三张核心表定位锁等待关系</li><li>从锁等待 → 事务 → SQL → 线程 → 业务代码的完整排查路径</li><li>MySQL 5.7 与 8.0 在锁排查工具上的关键差异</li></ul><hr><h2 id="一、锁超时问题复现" tabindex="-1"><a class="header-anchor" href="#一、锁超时问题复现"><span>一、锁超时问题复现</span></a></h2><h3 id="_1-1-场景模拟" tabindex="-1"><a class="header-anchor" href="#_1-1-场景模拟"><span>1.1 场景模拟</span></a></h3><p>创建一张用户表并插入测试数据：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">\`</span>user<span class="token punctuation">\`</span></span> <span class="token punctuation">(</span>
  <span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span> <span class="token keyword">int</span><span class="token punctuation">(</span><span class="token number">11</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;主键ID&#39;</span><span class="token punctuation">,</span>
  <span class="token identifier"><span class="token punctuation">\`</span>name<span class="token punctuation">\`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">50</span><span class="token punctuation">)</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token string">&#39;&#39;</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;姓名&#39;</span><span class="token punctuation">,</span>
  <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">\`</span>id<span class="token punctuation">\`</span></span><span class="token punctuation">)</span>
<span class="token punctuation">)</span> <span class="token keyword">ENGINE</span><span class="token operator">=</span><span class="token keyword">InnoDB</span> <span class="token keyword">DEFAULT</span> <span class="token keyword">CHARSET</span><span class="token operator">=</span>utf8mb4<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-锁等待复现" tabindex="-1"><a class="header-anchor" href="#_1-2-锁等待复现"><span>1.2 锁等待复现</span></a></h3><p><strong>事务 1</strong>：更新 <code>id=1</code> 的用户姓名，<strong>不提交事务</strong>：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">BEGIN</span><span class="token punctuation">;</span>
<span class="token keyword">UPDATE</span> <span class="token keyword">user</span> <span class="token keyword">SET</span> name<span class="token operator">=</span><span class="token string">&#39;一灯&#39;</span> <span class="token keyword">WHERE</span> id<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>事务 2</strong>：删除 <code>id=1</code> 的数据，此时产生锁等待：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">BEGIN</span><span class="token punctuation">;</span>
<span class="token keyword">DELETE</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> <span class="token keyword">WHERE</span> id<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">;</span>
<span class="token comment">-- 阻塞等待... 50 秒后报错 Lock wait timeout exceeded</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p><strong>💡 核心提示</strong>：InnoDB 的行锁是通过索引实现的。如果 UPDATE/DELETE 语句没有走索引（全表扫描），会退化为<strong>表锁</strong>，影响范围更大。</p></blockquote><h3 id="_1-3-锁等待的底层原理" tabindex="-1"><a class="header-anchor" href="#_1-3-锁等待的底层原理"><span>1.3 锁等待的底层原理</span></a></h3>`,17)),t(s,{id:"mermaid-61",code:""}),n[1]||(n[1]=e(`<h2 id="二、锁等待排查三板斧" tabindex="-1"><a class="header-anchor" href="#二、锁等待排查三板斧"><span>二、锁等待排查三板斧</span></a></h2><h3 id="_2-1-第一步-查锁等待关系" tabindex="-1"><a class="header-anchor" href="#_2-1-第一步-查锁等待关系"><span>2.1 第一步：查锁等待关系</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> information_schema<span class="token punctuation">.</span>innodb_lock_waits<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这张表展示了<strong>谁在等谁</strong>的核心关系。关键字段：</p><table><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>requesting_trx_id</code></td><td>等待锁的事务 ID</td></tr><tr><td><code>blocking_trx_id</code></td><td>持有锁的事务 ID</td></tr><tr><td><code>requested_lock_id</code></td><td>请求的锁 ID</td></tr><tr><td><code>blocking_lock_id</code></td><td>阻塞的锁 ID</td></tr></tbody></table><h3 id="_2-2-第二步-查锁详情" tabindex="-1"><a class="header-anchor" href="#_2-2-第二步-查锁详情"><span>2.2 第二步：查锁详情</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> information_schema<span class="token punctuation">.</span>innodb_locks<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><blockquote><p><strong>⚠️ 注意</strong>：此表在 <strong>MySQL 8.0 中已被移除</strong>，改用 <code>performance_schema.data_locks</code>。</p></blockquote><p>关键字段说明：</p><table><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>lock_trx_id</code></td><td>持有锁的事务 ID</td></tr><tr><td><code>lock_mode</code></td><td>锁模式：X（排他锁）/ S（共享锁）</td></tr><tr><td><code>lock_type</code></td><td>锁类型：RECORD（记录锁）/ TABLE（表锁）</td></tr><tr><td><code>lock_table</code></td><td>被锁的表名</td></tr><tr><td><code>lock_index</code></td><td>锁使用的索引名</td></tr><tr><td><code>lock_data</code></td><td>锁定的具体数据（主键值）</td></tr></tbody></table><h3 id="_2-3-第三步-查活跃事务" tabindex="-1"><a class="header-anchor" href="#_2-3-第三步-查活跃事务"><span>2.3 第三步：查活跃事务</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> information_schema<span class="token punctuation">.</span>innodb_trx<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这张表展示所有<strong>正在执行的事务</strong>，关键字段：</p><table><thead><tr><th>字段</th><th>含义</th></tr></thead><tbody><tr><td><code>trx_id</code></td><td>事务 ID</td></tr><tr><td><code>trx_state</code></td><td>事务状态：<code>RUNNING</code> / <code>LOCK WAIT</code></td></tr><tr><td><code>trx_started</code></td><td>事务开始时间</td></tr><tr><td><code>trx_mysql_thread_id</code></td><td>MySQL 线程 ID（用于 KILL）</td></tr><tr><td><code>trx_query</code></td><td>当前正在执行的 SQL</td></tr></tbody></table><blockquote><p><strong>💡 核心提示</strong>：找到 <code>trx_state = &#39;LOCK WAIT&#39;</code> 的行，就知道谁在等锁。根据 <code>trx_mysql_thread_id</code> 可以直接 <code>KILL</code> 该线程。</p></blockquote><h2 id="三、从锁定位到业务代码" tabindex="-1"><a class="header-anchor" href="#三、从锁定位到业务代码"><span>三、从锁定位到业务代码</span></a></h2><h3 id="_3-1-完整排查链路" tabindex="-1"><a class="header-anchor" href="#_3-1-完整排查链路"><span>3.1 完整排查链路</span></a></h3>`,17)),t(s,{id:"mermaid-264",code:""}),n[2]||(n[2]=e(`<h3 id="_3-2-具体操作步骤" tabindex="-1"><a class="header-anchor" href="#_3-2-具体操作步骤"><span>3.2 具体操作步骤</span></a></h3><p><strong>Step 1</strong>：根据 <code>blocking_trx_id</code> 找到持有锁的事务，获取其 <code>trx_mysql_thread_id</code>（比如 193）。</p><p><strong>Step 2</strong>：通过 MySQL 线程 ID 查找 Performance Schema 中的线程 ID：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>threads <span class="token keyword">WHERE</span> processlist_id <span class="token operator">=</span> <span class="token number">193</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>得到 <code>THREAD_ID</code>（比如 218）。</p><p><strong>Step 3</strong>：查找该线程正在执行的 SQL：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> THREAD_ID<span class="token punctuation">,</span> CURRENT_SCHEMA<span class="token punctuation">,</span> SQL_TEXT 
<span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>events_statements_current 
<span class="token keyword">WHERE</span> thread_id <span class="token operator">=</span> <span class="token number">218</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Step 4</strong>：拿到 SQL 后，在业务代码中搜索对应语句，定位到具体的方法调用。</p><h2 id="四、mysql-8-0-的变化" tabindex="-1"><a class="header-anchor" href="#四、mysql-8-0-的变化"><span>四、MySQL 8.0 的变化</span></a></h2><blockquote><p><strong>💡 核心提示</strong>：MySQL 8.0 对锁排查体系做了重大调整，<code>information_schema.innodb_locks</code> 和 <code>innodb_lock_waits</code> 已被废弃。</p></blockquote><h3 id="_4-1-替代方案" tabindex="-1"><a class="header-anchor" href="#_4-1-替代方案"><span>4.1 替代方案</span></a></h3><table><thead><tr><th>MySQL 5.7</th><th>MySQL 8.0</th></tr></thead><tbody><tr><td><code>information_schema.innodb_locks</code></td><td><code>performance_schema.data_locks</code></td></tr><tr><td><code>information_schema.innodb_lock_waits</code></td><td><code>performance_schema.data_lock_waits</code></td></tr><tr><td><code>information_schema.innodb_trx</code></td><td>仍然可用</td></tr></tbody></table><h3 id="_4-2-mysql-8-0-排查示例" tabindex="-1"><a class="header-anchor" href="#_4-2-mysql-8-0-排查示例"><span>4.2 MySQL 8.0 排查示例</span></a></h3><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 查询锁等待关系</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>data_lock_waits<span class="token punctuation">;</span>

<span class="token comment">-- 查询所有数据锁</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> performance_schema<span class="token punctuation">.</span>data_locks<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、生产环境避坑指南" tabindex="-1"><a class="header-anchor" href="#五、生产环境避坑指南"><span>五、生产环境避坑指南</span></a></h2><ol><li><strong>大事务是锁等待的元凶</strong>：事务越大、持有锁的时间越长，发生锁超时的概率越高。遵循<strong>短事务原则</strong>，尽快提交。</li><li><strong>避免长事务不提交</strong>：开发环境调试时开启了事务但忘记 COMMIT/ROLLBACK，连上生产库后成为&quot;隐形杀手&quot;。建议设置 <code>SET SESSION innodb_lock_wait_timeout = 10;</code> 缩短超时时间。</li><li><strong>索引缺失导致锁升级</strong>：如果 UPDATE/DELETE 语句没有使用索引，InnoDB 会扫描全表并加<strong>表级锁</strong>，严重影响并发。务必确保 WHERE 条件字段有索引。</li><li><strong>死锁和锁超时的区别</strong>：死锁（Deadlock）是 InnoDB 自动检测并回滚其中一个事务；锁超时是等待超过 <code>innodb_lock_wait_timeout</code> 后报错。前者是 InnoDB 主动处理，后者是被动超时。</li><li><strong>gap lock（间隙锁）的隐藏陷阱</strong>：在 RR（可重复读）隔离级别下，范围查询会加间隙锁。例如 <code>UPDATE user WHERE id &gt; 5</code> 不仅锁住已有记录，还会锁住 <code>id &gt; 5</code> 的间隙，导致新插入也被阻塞。</li><li><strong>外键约束会隐式加锁</strong>：如果表之间存在外键关系，UPDATE/DELETE 父表记录时会自动检查子表并加锁，这是很多锁等待问题的隐蔽原因。</li><li><strong>监控告警必须配置</strong>：建议监控 <code>information_schema.innodb_trx</code> 中事务数量和等待时间，超过阈值立即告警。</li></ol><h2 id="六、总结" tabindex="-1"><a class="header-anchor" href="#六、总结"><span>六、总结</span></a></h2><h3 id="_6-1-关键排查命令速查" tabindex="-1"><a class="header-anchor" href="#_6-1-关键排查命令速查"><span>6.1 关键排查命令速查</span></a></h3><table><thead><tr><th>命令</th><th>MySQL 5.7</th><th>MySQL 8.0</th><th>用途</th></tr></thead><tbody><tr><td>锁等待关系</td><td><code>innodb_lock_waits</code></td><td><code>data_lock_waits</code></td><td>谁在等谁</td></tr><tr><td>锁详情</td><td><code>innodb_locks</code></td><td><code>data_locks</code></td><td>锁的模式和范围</td></tr><tr><td>活跃事务</td><td><code>innodb_trx</code></td><td><code>innodb_trx</code></td><td>事务状态和线程ID</td></tr><tr><td>线程信息</td><td><code>threads</code></td><td><code>threads</code></td><td>线程ID映射</td></tr><tr><td>正在执行的SQL</td><td><code>events_statements_current</code></td><td><code>events_statements_current</code></td><td>获取SQL语句</td></tr></tbody></table><h3 id="_6-2-行动清单" tabindex="-1"><a class="header-anchor" href="#_6-2-行动清单"><span>6.2 行动清单</span></a></h3><ol><li><strong>设置合理的锁超时时间</strong>：<code>SET GLOBAL innodb_lock_wait_timeout = 30;</code>（默认 50 秒，建议缩短到 10-30 秒）。</li><li><strong>开启慢查询日志</strong>：记录执行时间长的 SQL，提前发现潜在的锁竞争问题。</li><li><strong>定期检查长事务</strong>：编写定时任务，监控 <code>information_schema.innodb_trx</code> 中运行超过阈值的事务。</li><li><strong>代码层面控制事务粒度</strong>：事务内只包含必要的数据库操作，避免在事务中做 HTTP 调用或耗时计算。</li><li><strong>排查时遵循标准链路</strong>：<code>innodb_lock_waits</code> → <code>innodb_trx</code> → <code>threads</code> → <code>events_statements_current</code> → 业务代码。</li><li><strong>升级到 MySQL 8.0 的同学注意</strong>：锁排查表已迁移到 <code>performance_schema</code>，需要更新排查脚本。</li><li><strong>建立锁告警机制</strong>：当等待锁的连接数超过 5 个或等待时间超过 10 秒时，触发告警通知。</li></ol>`,21))])}const u=a(c,[["render",r],["__file","timeout.html.vue"]]),h=JSON.parse('{"path":"/mysql/timeout.html","title":"","lang":"zh-CN","frontmatter":{"description":"引言 线上订单突然无法取消，排查半小时才发现是 MySQL 锁超时。 这种问题在生产环境并不罕见——一个未提交的事务持有行锁，后续所有请求全部阻塞，直到 innodb_lock_wait_timeout（默认 50 秒）超时报错。更可怕的是，如果找不到持有锁的事务，你连 kill 都不知道该 kill 哪个。 本文带你完整走一遍 MySQL 锁超时的排...","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/mysql/timeout.html"}],["meta",{"property":"og:site_name","content":"Java八股文网"}],["meta",{"property":"og:description","content":"引言 线上订单突然无法取消，排查半小时才发现是 MySQL 锁超时。 这种问题在生产环境并不罕见——一个未提交的事务持有行锁，后续所有请求全部阻塞，直到 innodb_lock_wait_timeout（默认 50 秒）超时报错。更可怕的是，如果找不到持有锁的事务，你连 kill 都不知道该 kill 哪个。 本文带你完整走一遍 MySQL 锁超时的排..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-18T07:28:17.000Z"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:modified_time","content":"2026-04-18T07:28:17.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-04-18T07:28:17.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"引言","slug":"引言","link":"#引言","children":[]},{"level":2,"title":"一、锁超时问题复现","slug":"一、锁超时问题复现","link":"#一、锁超时问题复现","children":[{"level":3,"title":"1.1 场景模拟","slug":"_1-1-场景模拟","link":"#_1-1-场景模拟","children":[]},{"level":3,"title":"1.2 锁等待复现","slug":"_1-2-锁等待复现","link":"#_1-2-锁等待复现","children":[]},{"level":3,"title":"1.3 锁等待的底层原理","slug":"_1-3-锁等待的底层原理","link":"#_1-3-锁等待的底层原理","children":[]}]},{"level":2,"title":"二、锁等待排查三板斧","slug":"二、锁等待排查三板斧","link":"#二、锁等待排查三板斧","children":[{"level":3,"title":"2.1 第一步：查锁等待关系","slug":"_2-1-第一步-查锁等待关系","link":"#_2-1-第一步-查锁等待关系","children":[]},{"level":3,"title":"2.2 第二步：查锁详情","slug":"_2-2-第二步-查锁详情","link":"#_2-2-第二步-查锁详情","children":[]},{"level":3,"title":"2.3 第三步：查活跃事务","slug":"_2-3-第三步-查活跃事务","link":"#_2-3-第三步-查活跃事务","children":[]}]},{"level":2,"title":"三、从锁定位到业务代码","slug":"三、从锁定位到业务代码","link":"#三、从锁定位到业务代码","children":[{"level":3,"title":"3.1 完整排查链路","slug":"_3-1-完整排查链路","link":"#_3-1-完整排查链路","children":[]},{"level":3,"title":"3.2 具体操作步骤","slug":"_3-2-具体操作步骤","link":"#_3-2-具体操作步骤","children":[]}]},{"level":2,"title":"四、MySQL 8.0 的变化","slug":"四、mysql-8-0-的变化","link":"#四、mysql-8-0-的变化","children":[{"level":3,"title":"4.1 替代方案","slug":"_4-1-替代方案","link":"#_4-1-替代方案","children":[]},{"level":3,"title":"4.2 MySQL 8.0 排查示例","slug":"_4-2-mysql-8-0-排查示例","link":"#_4-2-mysql-8-0-排查示例","children":[]}]},{"level":2,"title":"五、生产环境避坑指南","slug":"五、生产环境避坑指南","link":"#五、生产环境避坑指南","children":[]},{"level":2,"title":"六、总结","slug":"六、总结","link":"#六、总结","children":[{"level":3,"title":"6.1 关键排查命令速查","slug":"_6-1-关键排查命令速查","link":"#_6-1-关键排查命令速查","children":[]},{"level":3,"title":"6.2 行动清单","slug":"_6-2-行动清单","link":"#_6-2-行动清单","children":[]}]}],"git":{"createdTime":1745907928000,"updatedTime":1776497297000,"contributors":[{"name":"Yideng","email":"oointer@163.com","commits":2}]},"readingTime":{"minutes":5.67,"words":1701},"filePathRelative":"mysql/timeout.md","localizedDate":"2025年4月29日","autoDesc":true}');export{u as comp,h as data};
